const WebSocket = require('ws');
const crypto = require('crypto');

class RTSGameServer {
  constructor(port = 8080) {
    this.wss = new WebSocket.Server({ port });
    this.players = new Map();
    this.games = new Map();
    this.sessions = new Map();
    
    this.wss.on('connection', (ws) => this.handleConnection(ws));
    console.log(`RTS Game Server running on port ${port}`);
  }

  handleConnection(ws) {
    const sessionId = this.generateSecureToken();
    const playerId = this.generateSecureToken();
    
    const playerState = {
      id: playerId,
      sessionId: sessionId,
      ws: ws,
      authenticated: false,
      gameId: null,
      resources: { gold: 1000, wood: 500 },
      units: [],
      buildings: [],
      commandNonces: new Set(),
      lastCommandTime: Date.now(),
      commandCount: 0
    };

    this.players.set(playerId, playerState);
    this.sessions.set(sessionId, playerId);

    ws.on('message', (message) => this.handleMessage(playerId, message));
    ws.on('close', () => this.handleDisconnect(playerId));
    ws.on('error', (error) => {
      console.error('WebSocket error:', error.message);
      this.handleDisconnect(playerId);
    });

    this.sendMessage(ws, {
      type: 'connected',
      sessionId: sessionId,
      playerId: playerId
    });
  }

  generateSecureToken() {
    return crypto.randomBytes(32).toString('hex');
  }

  handleMessage(playerId, message) {
    const player = this.players.get(playerId);
    if (!player) return;

    let data;
    try {
      const messageStr = message.toString('utf8');
      if (messageStr.length > 10000) {
        this.sendError(player.ws, 'Message too large');
        return;
      }
      data = JSON.parse(messageStr);
    } catch (e) {
      this.sendError(player.ws, 'Invalid message format');
      return;
    }

    if (!this.validateMessageStructure(data)) {
      this.sendError(player.ws, 'Invalid message structure');
      return;
    }

    if (!this.checkRateLimit(player)) {
      this.sendError(player.ws, 'Rate limit exceeded');
      return;
    }

    if (!this.validateNonce(player, data.nonce)) {
      this.sendError(player.ws, 'Invalid or duplicate nonce');
      return;
    }

    switch (data.type) {
      case 'authenticate':
        this.handleAuthenticate(player, data);
        break;
      case 'join_game':
        this.handleJoinGame(player, data);
        break;
      case 'build':
        this.handleBuild(player, data);
        break;
      case 'attack':
        this.handleAttack(player, data);
        break;
      case 'move':
        this.handleMove(player, data);
        break;
      default:
        this.sendError(player.ws, 'Unknown command type');
    }
  }

  validateMessageStructure(data) {
    if (typeof data !== 'object' || data === null) return false;
    if (typeof data.type !== 'string') return false;
    if (typeof data.nonce !== 'string') return false;
    if (data.nonce.length < 16 || data.nonce.length > 128) return false;
    
    const allowedTypes = ['authenticate', 'join_game', 'build', 'attack', 'move'];
    return allowedTypes.includes(data.type);
  }

  validateNonce(player, nonce) {
    if (player.commandNonces.has(nonce)) {
      return false;
    }
    
    player.commandNonces.add(nonce);
    
    if (player.commandNonces.size > 1000) {
      const noncesArray = Array.from(player.commandNonces);
      player.commandNonces = new Set(noncesArray.slice(-500));
    }
    
    return true;
  }

  checkRateLimit(player) {
    const now = Date.now();
    const timeDiff = now - player.lastCommandTime;
    
    if (timeDiff < 1000) {
      player.commandCount++;
      if (player.commandCount > 20) {
        return false;
      }
    } else {
      player.commandCount = 1;
      player.lastCommandTime = now;
    }
    
    return true;
  }

  handleAuthenticate(player, data) {
    if (!data.token || typeof data.token !== 'string') {
      this.sendError(player.ws, 'Invalid authentication token');
      return;
    }

    const isValid = this.validateAuthToken(data.token);
    
    if (isValid) {
      player.authenticated = true;
      this.sendMessage(player.ws, {
        type: 'authenticated',
        success: true
      });
    } else {
      this.sendError(player.ws, 'Authentication failed');
    }
  }

  validateAuthToken(token) {
    if (typeof token !== 'string' || token.length < 32) return false;
    return /^[a-f0-9]{64}$/.test(token);
  }

  handleJoinGame(player, data) {
    if (!player.authenticated) {
      this.sendError(player.ws, 'Not authenticated');
      return;
    }

    if (!data.gameId || typeof data.gameId !== 'string') {
      this.sendError(player.ws, 'Invalid game ID');
      return;
    }

    const gameId = this.sanitizeString(data.gameId);
    
    if (!this.games.has(gameId)) {
      this.games.set(gameId, {
        id: gameId,
        players: new Set(),
        state: {}
      });
    }

    const game = this.games.get(gameId);
    
    if (game.players.size >= 8) {
      this.sendError(player.ws, 'Game is full');
      return;
    }

    game.players.add(player.id);
    player.gameId = gameId;

    this.sendMessage(player.ws, {
      type: 'joined_game',
      gameId: gameId,
      playerState: this.getPlayerPublicState(player)
    });
  }

  handleBuild(player, data) {
    if (!this.validatePlayerInGame(player)) return;

    if (!data.buildingType || typeof data.buildingType !== 'string') {
      this.sendError(player.ws, 'Invalid building type');
      return;
    }

    if (!this.validateCoordinates(data.x, data.y)) {
      this.sendError(player.ws, 'Invalid coordinates');
      return;
    }

    const allowedBuildings = ['barracks', 'farm', 'tower', 'wall'];
    const buildingType = this.sanitizeString(data.buildingType);
    
    if (!allowedBuildings.includes(buildingType)) {
      this.sendError(player.ws, 'Invalid building type');
      return;
    }

    const costs = {
      barracks: { gold: 200, wood: 150 },
      farm: { gold: 100, wood: 50 },
      tower: { gold: 150, wood: 100 },
      wall: { gold: 50, wood: 75 }
    };

    const cost = costs[buildingType];
    
    if (player.resources.gold < cost.gold || player.resources.wood < cost.wood) {
      this.sendError(player.ws, 'Insufficient resources');
      return;
    }

    player.resources.gold -= cost.gold;
    player.resources.wood -= cost.wood;

    const building = {
      id: this.generateSecureToken(),
      type: buildingType,
      x: Math.floor(data.x),
      y: Math.floor(data.y),
      health: 100,
      ownerId: player.id
    };

    player.buildings.push(building);

    this.sendMessage(player.ws, {
      type: 'build_success',
      building: building,
      resources: player.resources
    });

    this.broadcastToGame(player.gameId, {
      type: 'building_built',
      playerId: player.id,
      building: building
    }, player.id);
  }

  handleAttack(player, data) {
    if (!this.validatePlayerInGame(player)) return;

    if (!data.unitId || typeof data.unitId !== 'string') {
      this.sendError(player.ws, 'Invalid unit ID');
      return;
    }

    if (!data.targetId || typeof data.targetId !== 'string') {
      this.sendError(player.ws, 'Invalid target ID');
      return;
    }

    const unitId = this.sanitizeString(data.unitId);
    const targetId = this.sanitizeString(data.targetId);

    const unit = player.units.find(u => u.id === unitId);
    
    if (!unit) {
      this.sendError(player.ws, 'Unit not found');
      return;
    }

    const game = this.games.get(player.gameId);
    let target = null;
    let targetOwnerId = null;

    for (const otherPlayerId of game.players) {
      if (otherPlayerId === player.id) continue;
      
      const otherPlayer = this.players.get(otherPlayerId);
      if (!otherPlayer) continue;

      target = otherPlayer.units.find(u => u.id === targetId) ||
               otherPlayer.buildings.find(b => b.id === targetId);
      
      if (target) {
        targetOwnerId = otherPlayerId;
        break;
      }
    }

    if (!target) {
      this.sendError(player.ws, 'Target not found');
      return;
    }

    const damage = Math.floor(Math.random() * 20) + 10;
    target.health -= damage;

    this.sendMessage(player.ws, {
      type: 'attack_success',
      unitId: unitId,
      targetId: targetId,
      damage: damage
    });

    if (targetOwnerId) {
      const targetPlayer = this.players.get(targetOwnerId);
      if (targetPlayer && targetPlayer.ws.readyState === WebSocket.OPEN) {
        this.sendMessage(targetPlayer.ws, {
          type: 'under_attack',
          targetId: targetId,
          attackerId: unitId,
          damage: damage,
          remainingHealth: target.health
        });
      }
    }
  }

  handleMove(player, data) {
    if (!this.validatePlayerInGame(player)) return;

    if (!data.unitId || typeof data.unitId !== 'string') {
      this.sendError(player.ws, 'Invalid unit ID');
      return;
    }

    if (!this.validateCoordinates(data.x, data.y)) {
      this.sendError(player.ws, 'Invalid coordinates');
      return;
    }

    const unitId = this.sanitizeString(data.unitId);
    const unit = player.units.find(u => u.id === unitId);
    
    if (!unit) {
      this.sendError(player.ws, 'Unit not found');
      return;
    }

    unit.x = Math.floor(data.x);
    unit.y = Math.floor(data.y);

    this.sendMessage(player.ws, {
      type: 'move_success',
      unitId: unitId,
      x: unit.x,
      y: unit.y
    });

    this.broadcastToGame(player.gameId, {
      type: 'unit_moved',
      playerId: player.id,
      unitId: unitId,
      x: unit.x,
      y: unit.y
    }, player.id);
  }

  validatePlayerInGame(player) {
    if (!player.authenticated) {
      this.sendError(player.ws, 'Not authenticated');
      return false;
    }

    if (!player.gameId) {
      this.sendError(player.ws, 'Not in a game');
      return false;
    }

    return true;
  }

  validateCoordinates(x, y) {
    if (typeof x !== 'number' || typeof y !== 'number') return false;
    if (!Number.isFinite(x) || !Number.isFinite(y)) return false;
    if (x < 0 || x > 10000 || y < 0 || y > 10000) return false;
    return true;
  }

  sanitizeString(str) {
    if (typeof str !== 'string') return '';
    return str.replace(/[^a-zA-Z0-9_-]/g, '').substring(0, 64);
  }

  getPlayerPublicState(player) {
    return {
      id: player.id,
      resources: player.resources,
      unitCount: player.units.length,
      buildingCount: player.buildings.length
    };
  }

  broadcastToGame(gameId, message, excludePlayerId = null) {
    const game = this.games.get(gameId);
    if (!game) return;

    for (const playerId of game.players) {
      if (playerId === excludePlayerId) continue;
      
      const player = this.players.get(playerId);
      if (player && player.ws.readyState === WebSocket.OPEN) {
        this.sendMessage(player.ws, message);
      }
    }
  }

  sendMessage(ws, data) {
    if (ws.readyState === WebSocket.OPEN) {
      try {
        ws.send(JSON.stringify(data));
      } catch (e) {
        console.error('Error sending message:', e.message);
      }
    }
  }

  sendError(ws, message) {
    this.sendMessage(ws, {
      type: 'error',
      message: message
    });
  }

  handleDisconnect(playerId) {
    const player = this.players.get(playerId);
    if (!player) return;

    if (player.gameId) {
      const game = this.games.get(player.gameId);
      if (game) {
        game.players.delete(playerId);
        
        this.broadcastToGame(player.gameId, {
          type: 'player_disconnected',
          playerId: playerId
        });

        if (game.players.size === 0) {
          this.games.delete(player.gameId);
        }
      }
    }

    this.sessions.delete(player.sessionId);
    this.players.delete(playerId);
  }
}

const server = new RTSGameServer(8080);